+			if rcErr == nil {
+				gitAdd = rc.GitCmdCWD(ctx, "add", f)
+			} else {
+				// #nosec G204 -- f comes from jsonlFiles (hardcoded)
+				gitAdd = exec.Command("git", "add", f)
+			}
+			_ = gitAdd.Run()
+		}
+	}
+}
